//! `pmm` — M6: the physical FRAME allocator over the active boot memory map.
//!
//! Hands out / reclaims 4 KiB physical frames from USABLE RAM only — never the
//! kernel image (which now INCLUDES M5's 2 MiB `.bss` heap arena, so reserving
//! the image span covers it), the boot structures, sub-1 MiB on x86_64, or
//! device MMIO. Built on M3 (the identity map is live) and M5 (`alloc` is
//! online), so the cumulative boot M0..M5 is untouched.
//!
//! Framekernel rule (KERNEL-FOUNDATION-SPEC.md §1): every raw memory access
//! lives here in tb-hal. THIS module owns the intrusive free-frame stack, the
//! identity-mapped link writes, and the kernel-image linker-symbol read; the
//! per-arch boot-map READERS (PVH `hvm_start_info` / tb-boot `TbBootInfo` /
//! aarch64 QEMU-`virt` map) live in `arch/<arch>/pmm.rs` behind one
//! [`pmm_collect_regions`](crate::arch::pmm_collect_regions) contract. The
//! `kernel` crate stays `#![forbid(unsafe_code)]`: it only calls the safe
//! facade ([`crate::pmm_init`], [`crate::frame_alloc`], [`crate::frame_free`],
//! the stats and [`crate::pmm_selftest`]) and compares the returned `u64`
//! physical addresses — it can never dereference a frame.
//!
//! ALGORITHM — an INTRUSIVE FREE-FRAME STACK (ROADMAP-V2 M6). Each free 4 KiB
//! frame stores the physical address of the next free frame in its OWN first 8
//! bytes, written through the frame's identity-mapped address (PA == VA inside
//! the M3 identity region: `[0, 1 GiB)` on x86_64, `[0x4000_0000, 0x8000_0000)`
//! on aarch64). [`PmmState::head`] is the top of the stack; `0` is the empty
//! sentinel (frame PA 0 is never usable — x86_64 reserves sub-1 MiB, aarch64
//! RAM starts at 0x4000_0000). Allocation is an O(1) pop; free is an O(1) push;
//! there is NO per-frame bitmap. Exhaustion fail-closes to `None`.
//!
//! DOUBLE-FREE — with no per-frame ownership bit the stack can only reject the
//! O(1)-detectable misuse: a misaligned / out-of-range PA, a PA inside a
//! reservation, a free when nothing is allocated, or a free of the current
//! stack top. A well-formed double-free of a frame buried MID-stack is not
//! detectable in O(1) and is accepted — the documented cost of a bitmap-less
//! O(1) allocator (a debug allocated-set is a post-M6 option). No kernel path
//! frees a frame it does not currently hold, so this cannot manifest in M6.
//!
//! SEEDING — at [`PmmState::init`] every 4 KiB frame fully inside a parsed
//! usable range AND disjoint from every reservation is pushed onto the stack,
//! once. `total_frames` is that count (`sum(usable ranges) − reservations`, the
//! stat the self-test asserts on); `free_count` tracks the live free total. If
//! the reservation table ever overflows (see [`RegionSink`]) the seed fails
//! CLOSED — `total_frames` stays 0 — rather than risk handing out a reservation.
//!
//! SINGLE-CORE ASSUMPTION — identical to `heap.rs`: an [`UnsafeCell`] of the
//! state guarded by an [`AtomicBool`]. M0..M6 run single-threaded with
//! interrupts masked (M8 adds the first IRQ); the allocator never re-enters, so
//! the guard is always uncontended. When M8 lands preemption this critical
//! section must additionally mask interrupts — the same one-line change noted
//! in `heap.rs`.

use core::cell::UnsafeCell;
use core::sync::atomic::{AtomicBool, Ordering};

/// Bytes per physical frame (4 KiB granule, both architectures).
const FRAME: u64 = 4096;

/// Maximum number of distinct usable-RAM ranges the parser may report. PVH
/// E820 maps split RAM into a handful of entries; tb-boot/aarch64 use one.
const MAX_RANGES: usize = 16;

/// Maximum number of reservation spans (sub-1 MiB, the kernel image, every boot
/// structure, and any non-RAM hole inside a RAM range). Generously sized so a
/// rich E820 map never overflows it.
const MAX_RESV: usize = 64;

// ===========================================================================
// Physical ranges + the arch->pmm collection sink
// ===========================================================================

/// A half-open physical span `[base, base + len)`.
#[derive(Clone, Copy)]
struct PhysRange {
    /// Physical base address.
    base: u64,
    /// Length in bytes.
    len: u64,
}

impl PhysRange {
    /// The empty range, for `const` array initialisers.
    const ZERO: PhysRange = PhysRange { base: 0, len: 0 };

    /// One-past-the-end physical address (saturating, so a pathological `len`
    /// can never wrap into a false-negative overlap test).
    fn end(&self) -> u64 {
        self.base.saturating_add(self.len)
    }
}

/// The collection target the per-arch [`pmm_collect_regions`] fills.
///
/// The arch reader pushes USABLE RAM ranges (already clamped to its identity
/// window) and RESERVED spans (boot structures, sub-1 MiB on x86_64, the DTB on
/// aarch64, any non-RAM hole). [`PmmState::init`] then adds the kernel-image
/// reservation and seeds the free-frame stack from the difference. A dropped
/// USABLE range only under-seeds (fail-safe); a dropped RESERVATION could
/// expose reserved memory, so an overflow of the reservation table sets
/// [`RegionSink::overflow`] and makes `init` fail closed.
pub(crate) struct RegionSink {
    usable: [PhysRange; MAX_RANGES],
    usable_len: usize,
    reserved: [PhysRange; MAX_RESV],
    reserved_len: usize,
    /// Set when a reservation could not be recorded because the table filled.
    /// `PmmState::init` refuses to seed (fail-closed) when this is set, so a
    /// silently-dropped reservation can never be handed out as a free frame.
    overflow: bool,
}

impl RegionSink {
    /// A new, empty sink.
    fn new() -> Self {
        RegionSink {
            usable: [PhysRange::ZERO; MAX_RANGES],
            usable_len: 0,
            reserved: [PhysRange::ZERO; MAX_RESV],
            reserved_len: 0,
            overflow: false,
        }
    }

    /// Record a usable-RAM span `[base, base + len)`. Zero-length spans are
    /// ignored; a table overflow silently drops the span (fail-SAFE: dropping a
    /// usable range only under-seeds, never exposes memory). The arch reader is
    /// responsible for clamping to its identity-mapped window.
    pub(crate) fn push_usable(&mut self, base: u64, len: u64) {
        if len == 0 {
            return;
        }
        if self.usable_len < MAX_RANGES {
            self.usable[self.usable_len] = PhysRange { base, len };
            self.usable_len += 1;
        }
    }

    /// Record a reserved span `[base, base + len)` that must be carved out of
    /// usable RAM. Zero-length spans are ignored; a table overflow sets
    /// [`RegionSink::overflow`] (fail-CLOSED) instead of silently dropping the
    /// span, because a dropped reservation could otherwise be seeded as a free
    /// frame.
    pub(crate) fn push_reserved(&mut self, base: u64, len: u64) {
        if len == 0 {
            return;
        }
        if self.reserved_len < MAX_RESV {
            self.reserved[self.reserved_len] = PhysRange { base, len };
            self.reserved_len += 1;
        } else {
            self.overflow = true;
        }
    }
}

// ===========================================================================
// Pure arithmetic helpers
// ===========================================================================

/// Round `x` up to the next multiple of `a` (a power of two).
fn align_up(x: u64, a: u64) -> u64 {
    (x.saturating_add(a - 1)) & !(a - 1)
}

/// Round `x` down to the previous multiple of `a` (a power of two).
fn align_down(x: u64, a: u64) -> u64 {
    x & !(a - 1)
}

// ===========================================================================
// Kernel-image span (linker symbols)
// ===========================================================================

/// The whole-kernel-image span `[__image_start, __image_end)`, exported by both
/// linker scripts (`kernel/linker/{x86_64,aarch64}.ld`). It covers `.text`,
/// `.rodata`, `.data`, and `.bss` — and `.bss` holds M5's 2 MiB heap arena, the
/// x86_64 boot page tables/stacks and every tb-hal `.bss` static — so reserving
/// this single span keeps the frame allocator off ALL of them.
fn kernel_image_span() -> (u64, u64) {
    extern "C" {
        static __image_start: u8;
        static __image_end: u8;
    }
    // SAFETY: `__image_start`/`__image_end` are absolute symbols the linker
    // script defines at the image bounds. `addr_of!` forms a raw pointer to the
    // symbol WITHOUT reading it (no load occurs), so taking their addresses is
    // sound; we only compare the resulting integers.
    unsafe {
        let start = core::ptr::addr_of!(__image_start) as u64;
        let end = core::ptr::addr_of!(__image_end) as u64;
        (start, end)
    }
}

// ===========================================================================
// Intrusive free-frame link accessors (the only frame derefs)
// ===========================================================================

/// Write the next-free-PA link into a free frame's first 8 bytes, THROUGH its
/// identity-mapped address.
///
/// # Safety
/// `frame_pa` must be a 4 KiB-aligned physical frame inside the live M3
/// identity-mapped RAM window (so `PA == VA` and the first 8 bytes are mapped
/// read/write) and currently owned by the allocator (on, or being pushed onto,
/// the free stack), so this write cannot race or clobber live data.
unsafe fn write_link(frame_pa: u64, next: u64) {
    (frame_pa as *mut u64).write_volatile(next);
}

/// Read the next-free-PA link out of a free frame's first 8 bytes, through its
/// identity-mapped address.
///
/// # Safety
/// As [`write_link`]: `frame_pa` is an aligned, identity-mapped frame the
/// allocator owns (it is the current free-stack top).
unsafe fn read_link(frame_pa: u64) -> u64 {
    (frame_pa as *const u64).read_volatile()
}

// ===========================================================================
// Allocator state
// ===========================================================================

/// The mutable frame-allocator state. Only ever reached through [`PmmCell`]'s
/// guarded `&mut` borrow, so its intrusive `head` link is never aliased.
struct PmmState {
    /// Top of the intrusive free-frame stack (a physical frame address), or `0`
    /// when no free frame remains.
    head: u64,
    /// Parsed usable-RAM ranges (clamped to the identity window by the arch
    /// reader); the membership oracle for `frame_alloc`/`frame_free` validation.
    usable: [PhysRange; MAX_RANGES],
    /// Number of live entries in `usable`.
    usable_len: usize,
    /// Reservation spans carved out of usable RAM (boot structures, sub-1 MiB,
    /// the kernel image, device/non-RAM holes).
    reserved: [PhysRange; MAX_RESV],
    /// Number of live entries in `reserved`.
    reserved_len: usize,
    /// Frames seeded at init: `sum(usable ranges) − reservations`, the invariant
    /// the self-test checks. Constant after [`PmmState::init`].
    total_frames: usize,
    /// Frames currently on the free stack. `total_frames − (live allocations)`.
    free_count: usize,
    /// Whether [`PmmState::init`] has already parsed the map and seeded.
    initialized: bool,
}

impl PmmState {
    /// A zeroed, uninitialised state for a `const` static.
    const fn new() -> Self {
        PmmState {
            head: 0,
            usable: [PhysRange::ZERO; MAX_RANGES],
            usable_len: 0,
            reserved: [PhysRange::ZERO; MAX_RESV],
            reserved_len: 0,
            total_frames: 0,
            free_count: 0,
            initialized: false,
        }
    }

    /// Parse the active boot path's memory map and seed the free-frame stack.
    /// Idempotent (a second call is a no-op), so [`crate::pmm_init`] is safe to
    /// call once per boot without a double-seed hazard.
    fn init(&mut self, boot_info: usize) {
        if self.initialized {
            return;
        }

        let mut sink = RegionSink::new();
        // Per-arch reader: usable RAM (clamped to the identity window) + the
        // boot-structure / sub-1 MiB / DTB / device-hole reservations.
        crate::arch::pmm_collect_regions(boot_info, &mut sink);

        // Shared reservation: the whole kernel image — code/rodata/data/bss,
        // which INCLUDES M5's 2 MiB heap arena and the boot page tables/stacks.
        let (img_start, img_end) = kernel_image_span();
        if img_end > img_start {
            sink.push_reserved(img_start, img_end - img_start);
        }

        // Fail CLOSED on reservation-table overflow: a silently-dropped
        // reservation could otherwise be seeded as a usable frame. Leave the
        // allocator empty (`total_frames` == 0) so the kernel's M6 self-test
        // reports "no usable frames" instead of risking a bad handout. The three
        // real boot maps stay far under MAX_RESV, so this never trips in
        // practice; it is a hard backstop on the trusted reservation set.
        if sink.overflow {
            self.initialized = true;
            return;
        }

        self.usable_len = sink.usable_len;
        self.usable[..sink.usable_len].copy_from_slice(&sink.usable[..sink.usable_len]);
        self.reserved_len = sink.reserved_len;
        self.reserved[..sink.reserved_len].copy_from_slice(&sink.reserved[..sink.reserved_len]);

        self.seed();
        self.initialized = true;
    }

    /// Push every usable, non-reserved 4 KiB frame onto the intrusive stack.
    fn seed(&mut self) {
        self.head = 0;
        self.total_frames = 0;
        let mut i = 0;
        while i < self.usable_len {
            let r = self.usable[i];
            let mut f = align_up(r.base, FRAME);
            let end = align_down(r.end(), FRAME);
            while f < end {
                if f != 0 && !self.is_reserved_frame(f) {
                    // SAFETY: `f` is a 4 KiB-aligned frame fully inside a parsed
                    // usable range (so identity-mapped RAM) and disjoint from
                    // every reservation; linking it touches only its own first
                    // 8 bytes, which nothing else references at seed time.
                    unsafe {
                        write_link(f, self.head);
                    }
                    self.head = f;
                    self.total_frames += 1;
                }
                f += FRAME;
            }
            i += 1;
        }
        self.free_count = self.total_frames;
    }

    /// `true` iff the frame `[f, f + FRAME)` intersects any reservation.
    fn is_reserved_frame(&self, f: u64) -> bool {
        // `saturating_add` so a top-of-space `f` can never panic on overflow;
        // it saturates to u64::MAX and the `f < r.end()` half of the overlap
        // test (every reservation end is finite, far below u64::MAX) is false,
        // so no false positive results.
        let fe = f.saturating_add(FRAME);
        let mut i = 0;
        while i < self.reserved_len {
            let r = self.reserved[i];
            if f < r.end() && r.base < fe {
                return true;
            }
            i += 1;
        }
        false
    }

    /// `true` iff `pa` lies inside some parsed usable-RAM range.
    fn addr_in_usable(&self, pa: u64) -> bool {
        let mut i = 0;
        while i < self.usable_len {
            let r = self.usable[i];
            if pa >= r.base && pa < r.end() {
                return true;
            }
            i += 1;
        }
        false
    }

    /// `true` iff `pa` lies inside some reservation span.
    fn addr_reserved(&self, pa: u64) -> bool {
        let mut i = 0;
        while i < self.reserved_len {
            let r = self.reserved[i];
            if pa >= r.base && pa < r.end() {
                return true;
            }
            i += 1;
        }
        false
    }

    /// `true` iff the whole frame `[pa, pa + FRAME)` fits inside one usable range.
    fn frame_in_usable(&self, pa: u64) -> bool {
        // `checked_add` so a 4 KiB-aligned `pa` near `u64::MAX` is rejected
        // fail-closed instead of overflowing — a debug-build panic, or a release
        // wrap that could spuriously satisfy the `pe <= r.end()` range test and
        // let `frame_free` write a link word through an unmapped VA. The
        // framekernel boundary promises `frame_free` rejects out-of-range PAs;
        // this is where that promise is kept.
        let pe = match pa.checked_add(FRAME) {
            Some(v) => v,
            None => return false,
        };
        let mut i = 0;
        while i < self.usable_len {
            let r = self.usable[i];
            if pa >= r.base && pe <= r.end() {
                return true;
            }
            i += 1;
        }
        false
    }

    /// Pop the top free frame (O(1)). `None` when exhausted (fail-closed).
    fn alloc(&mut self) -> Option<u64> {
        if self.head == 0 {
            return None;
        }
        let pa = self.head;
        // SAFETY: `pa` is the current free-stack top — a frame the allocator
        // owns; reading its link word yields the next free PA (or `0`).
        let next = unsafe { read_link(pa) };
        self.head = next;
        self.free_count -= 1;
        Some(pa)
    }

    /// Push a frame back (O(1)). Returns `false` — fail-closed, no state change —
    /// for a misaligned/null PA, a PA not fully inside a usable range (incl. an
    /// out-of-range PA near `u64::MAX`, rejected via `frame_in_usable`'s
    /// checked add), a PA that intersects a reservation, a free of the current
    /// top (the cheap O(1) double-free guard), or a free when nothing is
    /// allocated.
    fn free(&mut self, pa: u64) -> bool {
        if pa == 0 || pa % FRAME != 0 {
            return false;
        }
        if !self.frame_in_usable(pa) {
            return false;
        }
        if self.is_reserved_frame(pa) {
            return false;
        }
        if self.free_count >= self.total_frames {
            return false; // nothing is allocated -> this must be a double-free
        }
        if self.head == pa {
            return false; // freeing the current top is an immediate double-free
        }
        // SAFETY: `pa` is a 4 KiB-aligned usable RAM frame previously handed out
        // by `alloc`; pushing it writes only its own link word.
        unsafe {
            write_link(pa, self.head);
        }
        self.head = pa;
        self.free_count += 1;
        true
    }
}

// ===========================================================================
// Guarded interior-mutable cell (the heap.rs `HeapCell` pattern)
// ===========================================================================

/// Interior-mutable, `Sync` wrapper around [`PmmState`].
struct PmmCell {
    state: UnsafeCell<PmmState>,
    lock: AtomicBool,
}

// SAFETY: the inner `PmmState` is reached only through `with`, which takes the
// `lock` before minting a `&mut`; on this single, non-preemptible core that
// guard hands out exclusive access, so the `UnsafeCell` is never aliased. (M8's
// first IRQ will require masking interrupts inside `with`; see the module doc.)
unsafe impl Sync for PmmCell {}

impl PmmCell {
    /// A new, unlocked, uninitialised cell for a `const` static.
    const fn new() -> Self {
        PmmCell {
            state: UnsafeCell::new(PmmState::new()),
            lock: AtomicBool::new(false),
        }
    }

    /// Run `f` with exclusive access to the [`PmmState`], under the guard.
    /// Single-core, non-reentrant: the CAS only ever succeeds uncontended.
    fn with<R>(&self, f: impl FnOnce(&mut PmmState) -> R) -> R {
        while self
            .lock
            .compare_exchange(false, true, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            core::hint::spin_loop();
        }
        // SAFETY: the CAS gives this core exclusive ownership of the cell for
        // the duration of `f`; nothing else can hold a `&mut` to the state.
        let state = unsafe { &mut *self.state.get() };
        let result = f(state);
        self.lock.store(false, Ordering::Release);
        result
    }
}

/// The single, crate-internal frame allocator.
static GLOBAL_PMM: PmmCell = PmmCell::new();

// ===========================================================================
// Crate-internal facade (lib.rs re-exports these as the safe public surface)
// ===========================================================================

/// Parse the active boot path's memory map and seed the allocator. Idempotent.
pub(crate) fn init(boot_info: usize) {
    GLOBAL_PMM.with(|s| s.init(boot_info));
}

/// Pop one 4 KiB physical frame, or `None` on exhaustion.
pub(crate) fn frame_alloc() -> Option<u64> {
    GLOBAL_PMM.with(|s| s.alloc())
}

/// Return a previously-allocated frame; `true` = accepted, `false` = rejected.
pub(crate) fn frame_free(pa: u64) -> bool {
    GLOBAL_PMM.with(|s| s.free(pa))
}

/// Total seeded frames (`sum(usable ranges) − reservations`).
pub(crate) fn total_frames() -> usize {
    GLOBAL_PMM.with(|s| s.total_frames)
}

/// Frames currently on the free stack.
pub(crate) fn free_frames() -> usize {
    GLOBAL_PMM.with(|s| s.free_count)
}

/// `true` iff `pa` lies inside a parsed usable-RAM range.
pub(crate) fn addr_in_usable_ram(pa: u64) -> bool {
    GLOBAL_PMM.with(|s| s.addr_in_usable(pa))
}

/// `true` iff `pa` lies inside any reservation span.
pub(crate) fn addr_reserved(pa: u64) -> bool {
    GLOBAL_PMM.with(|s| s.addr_reserved(pa))
}

/// Low-level frame self-test the `forbid(unsafe_code)` kernel cannot do itself:
/// allocate a frame, write a magic THROUGH its identity address (first word and
/// a word deep in the page), read both back, free it, and end at the entry
/// free-count (no leak). Returns `true` on pass.
pub(crate) fn selftest() -> bool {
    const MAGIC: u64 = 0x4D36_4672_616D_6531; // b"M6Frame1"

    let base_free = free_frames();
    let pa = match frame_alloc() {
        Some(p) => p,
        None => return false,
    };
    // A freshly handed-out frame must be 4 KiB-aligned and the free count must
    // have dropped by exactly one.
    if pa % FRAME != 0 || free_frames() != base_free - 1 {
        let _ = frame_free(pa);
        return false;
    }

    // SAFETY: `pa` is a 4 KiB-aligned, identity-mapped RAM frame this allocator
    // just handed out and still owns; both offsets stay inside its 4 KiB page.
    let read_ok = unsafe {
        write_link(pa, MAGIC); // first word (the link slot)
        let deep = (pa + FRAME - 8) as *mut u64;
        deep.write_volatile(!MAGIC); // last word of the page
        let first = read_link(pa);
        let last = (deep as *const u64).read_volatile();
        first == MAGIC && last == !MAGIC
    };

    let freed = frame_free(pa);
    read_ok && freed && free_frames() == base_free
}

//! x86_64 boot memory-map reader for M6 — the ONE place the boot-info pointer
//! is dereferenced on x86_64.
//!
//! Two boot paths feed the SAME frame allocator, and are DESIGNED TO CONVERGE
//! on the same usable set for the same guest (both reduce to
//! `[__image_end, top_of_RAM)` once the shared sub-1 MiB + kernel-image +
//! boot-structure reservations are applied; QEMU may additionally carve a few
//! E820-reserved holes, so the two sets COINCIDE in practice rather than being
//! guaranteed bit-identical — and the M6 marker test does not assert cross-path
//! equality):
//!  * **PVH** (QEMU `microvm` / Firecracker): `boot_info` = phys addr of a Xen
//!    `struct hvm_start_info`; its `memmap` is an E820-style array of
//!    `hvm_memmap_table_entry`. `type == 1` is usable RAM; everything else is
//!    reserved.
//!  * **tb-boot v0** (the project's `tb-vmm`): `boot_info` = phys addr of a
//!    `tb_boot::TbBootInfo`; we parse its `TbMemRegion` array with the crate's
//!    OWN typed `#[repr(C)]` readers + constants (no hand-coded offsets).
//!
//! The two are told apart exactly as `crate::read_boot_magic` does: the 8-byte
//! word at offset 0 equals `tb_boot::TB_BOOT_MAGIC` for tb-boot, or the PVH
//! magic `0x336E_C578` ("xEn3") for PVH.
//!
//! Every read is GUARDED to the identity-mapped low window `[0x1000, 1 GiB)`
//! that BOTH x86_64 boot paths establish (PVH `_start`'s `__boot_pd`; tb-vmm's
//! Firecracker-shaped 2 MiB-page identity tables), so a stray/foreign pointer
//! can never fault the boot path — it just yields `None` and the allocator
//! fail-closes to "no usable frames". Reads are byte-wise volatile, so no
//! alignment assumption is imposed on the foreign boot block, and every
//! data-derived pointer arithmetic uses `saturating_add`, so even a block that
//! happens to carry the PVH magic plus garbage pointers fail-closes rather than
//! panicking. This also bakes in the assumption that `hvm_start_info` AND its
//! `memmap` array sit below 1 GiB: the PVH ABI only mandates they live below
//! 4 GiB, but QEMU microvm / Firecracker stage them in low memory; anything
//! above 1 GiB simply fail-closes (no usable frames) instead of being misread.
//!
//! Verified layouts (cross-checked against the in-repo PVH note emitter
//! `arch/x86_64/boot.rs`, `crates/tb-boot`, and the Xen ABI):
//!  * `hvm_start_info` (xen/include/public/arch-x86/hvm/start_info.h):
//!    `magic@0(u32)=0x336EC578`, `version@4(u32)`, `flags@8`, `nr_modules@12`,
//!    `modlist_paddr@16(u64)`, `cmdline_paddr@24(u64)`, `rsdp_paddr@32(u64)`,
//!    `memmap_paddr@40(u64)`, `memmap_entries@48(u32)`, `reserved@52(u32)`
//!    (56 bytes total for v1). `memmap_paddr`/`memmap_entries` exist only for
//!    version >= 1, so the reader gates the memmap walk on the version.
//!  * `hvm_memmap_table_entry`: `addr@0(u64)`, `size@8(u64)`, `type@16(u32)`,
//!    `reserved@20(u32)` (24 bytes); `type == 1` = `XEN_HVM_MEMMAP_TYPE_RAM`.
//!  * `hvm_modlist_entry`: `paddr@0(u64)`, `size@8(u64)`,
//!    `cmdline_paddr@16(u64)`, `reserved@24(u64)` (32 bytes); each module's
//!    `[paddr, size)` is reserved so initrd-class RAM is never handed out.

use crate::pmm::RegionSink;
use tb_boot::{TbBootInfo, TbMemRegion, TB_BOOT_MAGIC};

/// Bytes per frame.
const FRAME: u64 = 4096;

/// Lowest physical address the guarded readers will touch (rejects the null
/// page). Mirrors `crate::read_boot_magic`'s `WINDOW_LO`.
const ID_LO: u64 = 0x1000;

/// First address PAST the identity-mapped low window: 1 GiB. Both x86_64 boot
/// paths identity-map `[0, 1 GiB)` with 2 MiB pages, so any read below this is
/// present, and any usable RAM above this is NOT reachable by the intrusive
/// link writes — hence the clamp in [`push_usable_clamped`].
const ID_HI: u64 = 0x4000_0000;

/// The PVH `hvm_start_info` magic ("xEn3").
const PVH_MAGIC: u32 = 0x336E_C578;

/// E820 / PVH memmap entry type for usable RAM.
const MEMMAP_TYPE_RAM: u32 = 1;

// ---------------------------------------------------------------------------
// Guarded volatile readers (the BootMemMap generalisation of read_boot_magic).
// ---------------------------------------------------------------------------

/// Read `buf.len()` bytes starting at physical `pa`, guarded to
/// `[ID_LO, ID_HI)`. `false` (leaving `buf` partially written but unused) if the
/// whole span does not fit inside the identity window.
fn read_bytes(pa: u64, buf: &mut [u8]) -> bool {
    let n = buf.len() as u64;
    if pa < ID_LO {
        return false;
    }
    match pa.checked_add(n) {
        Some(end) if end <= ID_HI => {}
        _ => return false,
    }
    let mut i = 0u64;
    while i < n {
        // SAFETY: `[pa, pa + n)` is inside `[ID_LO, ID_HI)`, which both x86_64
        // boot paths identity-map present; a `u8` read imposes no alignment and
        // `read_volatile` keeps the optimiser from reordering/eliding these
        // foreign, single-producer boot reads.
        buf[i as usize] = unsafe { ((pa + i) as *const u8).read_volatile() };
        i += 1;
    }
    true
}

/// Guarded little-endian `u32` read, or `None` if out of window.
fn read_u32(pa: u64) -> Option<u32> {
    let mut b = [0u8; 4];
    if read_bytes(pa, &mut b) {
        Some(u32::from_le_bytes(b))
    } else {
        None
    }
}

/// Guarded little-endian `u64` read, or `None` if out of window.
fn read_u64(pa: u64) -> Option<u64> {
    let mut b = [0u8; 8];
    if read_bytes(pa, &mut b) {
        Some(u64::from_le_bytes(b))
    } else {
        None
    }
}

// ---------------------------------------------------------------------------
// Range helpers (clamp everything to the identity window).
// ---------------------------------------------------------------------------

/// Push a usable RAM span, clamped to `[0, 1 GiB)`. The intrusive free-frame
/// links are written through identity addresses, which exist only inside the M3
/// identity map, so RAM above 1 GiB is deliberately dropped.
fn push_usable_clamped(sink: &mut RegionSink, base: u64, len: u64) {
    let end = base.saturating_add(len).min(ID_HI);
    if end > base {
        sink.push_usable(base, end - base);
    }
}

/// Reserve a span, clamped to `[0, 1 GiB)` so reservation bounds stay finite.
fn reserve_span(sink: &mut RegionSink, base: u64, len: u64) {
    if len == 0 {
        return;
    }
    let end = base.saturating_add(len).min(ID_HI);
    if end > base {
        sink.push_reserved(base, end - base);
    }
}

// ---------------------------------------------------------------------------
// The two boot-map readers.
// ---------------------------------------------------------------------------

/// Parse a tb-boot `TbBootInfo` (validated via the crate) into usable + reserved
/// spans. The boot block + region array + cmdline are all reserved.
fn collect_tb_boot(bi: u64, sink: &mut RegionSink) {
    let mut head = [0u8; TbBootInfo::SIZE];
    if !read_bytes(bi, &mut head) {
        return;
    }
    let info = match TbBootInfo::read_validated(&head) {
        Ok(i) => i,
        Err(_) => return,
    };

    // Reserve the boot structures themselves (tb-vmm places them below 1 MiB,
    // but reserve them explicitly so the policy is source-independent).
    reserve_span(sink, bi, TbBootInfo::SIZE as u64);
    let regions_ptr = info.mem_regions_ptr;
    let count = info.mem_regions_len;
    reserve_span(
        sink,
        regions_ptr,
        count.saturating_mul(TbMemRegion::SIZE as u64),
    );
    if info.cmdline_ptr != 0 && info.cmdline_len != 0 {
        reserve_span(sink, info.cmdline_ptr, info.cmdline_len);
    }

    let mut i = 0u64;
    while i < count {
        // `saturating_add`/`saturating_mul`: `regions_ptr` is unvalidated guest
        // data, so a garbage value must not overflow-panic — `read_bytes` then
        // guards the (possibly saturated) address and stops the walk.
        let rpa = regions_ptr.saturating_add(i.saturating_mul(TbMemRegion::SIZE as u64));
        let mut rb = [0u8; TbMemRegion::SIZE];
        if !read_bytes(rpa, &mut rb) {
            break;
        }
        if let Ok(r) = TbMemRegion::read_from_prefix(&rb) {
            if r.is_ram() {
                push_usable_clamped(sink, r.base, r.len);
            } else {
                reserve_span(sink, r.base, r.len);
            }
        }
        i += 1;
    }
}

/// Parse a PVH `hvm_start_info` memmap into usable + reserved spans.
fn collect_pvh(bi: u64, sink: &mut RegionSink) {
    match read_u32(bi) {
        Some(m) if m == PVH_MAGIC => {}
        _ => return, // not a PVH block either -> fail-closed (no usable frames)
    }

    // `memmap_paddr`@40 / `memmap_entries`@48 are version>=1 fields; a v0
    // start_info is only 40 bytes, so reading them would walk off the struct.
    // Gate the memmap walk on the version below (QEMU microvm + Firecracker
    // both emit version 1). The reservations just below use only v0 fields.
    let version = read_u32(bi + 4).unwrap_or(0);

    // Reserve the start_info block (v1 is 56 bytes) and the cmdline
    // (NUL-terminated; reserve one conservative page).
    reserve_span(sink, bi, 56);
    if let Some(cmdline) = read_u64(bi + 24) {
        if cmdline != 0 {
            reserve_span(sink, cmdline, FRAME);
        }
    }
    // Reserve any boot modules (initrd-class): both the `hvm_modlist_entry`
    // array itself AND each module's `[paddr, size)` payload, because the
    // hypervisor marks module RAM as memmap type==1 and it would otherwise be
    // seeded as usable. `hvm_modlist_entry` = { paddr@0, size@8, cmdline@16,
    // reserved@24 } (32 bytes); the walk is bounded against a corrupt count and
    // uses `saturating_add` on the data-derived `modlist` pointer.
    if let Some(nr_modules) = read_u32(bi + 12) {
        if nr_modules != 0 {
            if let Some(modlist) = read_u64(bi + 16) {
                reserve_span(sink, modlist, (nr_modules as u64).saturating_mul(32));
                let nmods = if nr_modules > 64 { 64 } else { nr_modules };
                let mut m = 0u64;
                while m < nmods as u64 {
                    let ment = modlist.saturating_add(m.saturating_mul(32));
                    if let (Some(mpaddr), Some(msize)) =
                        (read_u64(ment), read_u64(ment.saturating_add(8)))
                    {
                        reserve_span(sink, mpaddr, msize);
                    }
                    m += 1;
                }
            }
        }
    }

    // start_info v0 carries no memmap table -> fail-closed (no usable frames).
    if version < 1 {
        return;
    }

    let memmap = match read_u64(bi + 40) {
        Some(m) => m,
        None => return,
    };
    let entries = match read_u32(bi + 48) {
        Some(e) => e,
        None => return,
    };
    if memmap == 0 || entries == 0 {
        return;
    }
    reserve_span(sink, memmap, (entries as u64).saturating_mul(24));

    // Bound the walk so a corrupt `entries` can never run away.
    let n = if entries > 128 { 128 } else { entries };
    let mut i = 0u64;
    while i < n as u64 {
        // `saturating_add`/`saturating_mul`: `memmap` is unvalidated guest data,
        // so a garbage value must not overflow-panic — `read_u64` then guards
        // the (possibly saturated) address and stops the walk.
        let e = memmap.saturating_add(i.saturating_mul(24));
        let addr = match read_u64(e) {
            Some(a) => a,
            None => break,
        };
        let size = match read_u64(e + 8) {
            Some(s) => s,
            None => break,
        };
        let etype = match read_u32(e + 16) {
            Some(t) => t,
            None => break,
        };
        if etype == MEMMAP_TYPE_RAM {
            push_usable_clamped(sink, addr, size);
        } else {
            reserve_span(sink, addr, size);
        }
        i += 1;
    }
}

// ---------------------------------------------------------------------------
// The arch contract entry point.
// ---------------------------------------------------------------------------

/// Collect usable-RAM ranges + reservations for the active x86_64 boot path.
///
/// Always reserves the sub-1 MiB region (legacy/BIOS/boot scratch on x86_64),
/// then dispatches on the boot-info magic to the tb-boot or PVH reader. The
/// shared `pmm` layer adds the kernel-image reservation on top.
pub fn pmm_collect_regions(boot_info: usize, sink: &mut RegionSink) {
    // Sub-1 MiB is never handed out on x86_64 (real-mode IVT/BDA, EBDA, VGA,
    // option ROMs, and where tb-vmm stages its boot structures). Reserving it
    // here is what makes the PVH and tb-boot sources converge on one usable set.
    sink.push_reserved(0, 0x10_0000);

    let bi = boot_info as u64;
    if let Some(magic) = read_u64(bi) {
        if magic == TB_BOOT_MAGIC {
            collect_tb_boot(bi, sink);
            return;
        }
    }
    collect_pvh(bi, sink);
}

//! aarch64 boot memory-map source for M6 (QEMU `virt`).
//!
//! FALLBACK CHOSEN (per the ROADMAP-V2 M6 risk note): rather than a full
//! from-scratch no_std FDT *node* walker, this uses the HARD-CODED QEMU `virt`
//! RAM map — RAM = `[0x4000_0000, 0x4000_0000 + 128 MiB)` (the runner uses
//! `-m 128M`) — as the usable-RAM source, clamped to the M3 identity-mapped RAM
//! gigabyte `[0x4000_0000, 0x8000_0000)`. Because usable RAM is RANGE-restricted
//! to DRAM, every device MMIO window is excluded NATURALLY: the PL011 UART
//! (`0x0900_0000`), the GIC, and the virtio-mmio transports all sit BELOW
//! `0x4000_0000` and can never be handed out.
//!
//! The DTB is still reserved PRECISELY: the FDT header is big-endian, with
//! `magic@0 = 0xD00DFEED` and `totalsize@4`. We read those two words (guarded)
//! straight from the `boot_info` pointer QEMU left in `x0`, and reserve exactly
//! `[fdt, fdt + totalsize)` wherever QEMU placed the blob — plus the
//! conventional low-RAM staging window below the kernel image. A full
//! `/memory` + `/reserved-memory` FDT parse is the post-M6 upgrade; until then
//! the hard-coded map is the correct, bounded answer for the `virt` runner.
//!
//! Verified facts:
//!  * QEMU `virt` DRAM base `0x4000_0000`; the kernel links at `+512 KiB`
//!    (`0x4008_0000`, see `kernel/linker/aarch64.ld`); device MMIO is all below
//!    DRAM (QEMU `hw/arm/virt.c` memmap).
//!  * FDT header layout (Devicetree Specification v0.4 §5.2): big-endian
//!    `magic` then `totalsize` as the first two 32-bit words.

use crate::pmm::RegionSink;

/// QEMU `virt` DRAM base.
const DRAM_BASE: u64 = 0x4000_0000;

/// QEMU `virt` runner RAM size (`-m 128M`).
const DRAM_SIZE: u64 = 128 * 1024 * 1024;

/// Upper bound of the M3 identity-mapped RAM gigabyte (L1[1] Normal-WB block):
/// `[0x4000_0000, 0x8000_0000)`. Usable RAM is clamped here because the
/// intrusive free-frame links are written through identity addresses, and only
/// this gigabyte of RAM is identity-mapped.
const ID_RAM_HI: u64 = 0x8000_0000;

/// Kernel image link base (`KERNEL_LMA` in `kernel/linker/aarch64.ld`). The
/// 512 KiB of DRAM below it is where QEMU stages the DTB / boot params, so it is
/// reserved wholesale as a conservative DTB margin.
const IMAGE_LMA: u64 = 0x4008_0000;

/// FDT header magic, as a big-endian 32-bit word (Devicetree Spec §5.2).
const FDT_MAGIC: u32 = 0xD00D_FEED;

/// Guarded big-endian `u32` read inside the identity-mapped RAM gigabyte. The
/// QEMU `virt` DTB lives in DRAM, so the FDT header is reachable here; an
/// out-of-window pointer simply yields `None` (no DTB reservation, never a
/// fault).
fn read_be32(pa: u64) -> Option<u32> {
    if pa < DRAM_BASE {
        return None;
    }
    match pa.checked_add(4) {
        Some(end) if end <= ID_RAM_HI => {}
        _ => return None,
    }
    let mut b = [0u8; 4];
    let mut i = 0u64;
    while i < 4 {
        // SAFETY: `[pa, pa + 4)` is inside the identity-mapped Normal-WB RAM
        // gigabyte; a `u8` load imposes no alignment, and `read_volatile` keeps
        // the optimiser from reordering/eliding the foreign boot-blob read.
        b[i as usize] = unsafe { ((pa + i) as *const u8).read_volatile() };
        i += 1;
    }
    Some(u32::from_be_bytes(b))
}

/// FDT `totalsize` if `boot_info` points at a valid FDT header (magic matches
/// and the size is sane), else `None`.
fn fdt_totalsize(fdt: u64) -> Option<u32> {
    if read_be32(fdt)? != FDT_MAGIC {
        return None;
    }
    let total = read_be32(fdt + 4)?;
    // A QEMU `virt` DTB is well under 2 MiB; reject anything implausible so a
    // garbage read can never produce a giant reservation.
    if total == 0 || total > 0x20_0000 {
        return None;
    }
    Some(total)
}

/// Collect usable-RAM ranges + reservations for aarch64 (QEMU `virt`).
///
/// Usable RAM is the hard-coded `virt` map clamped to the identity gigabyte;
/// reservations are the low-RAM DTB staging window below the image plus the
/// exact DTB span (read from the FDT header). The shared `pmm` layer adds the
/// kernel-image reservation on top.
pub fn pmm_collect_regions(boot_info: usize, sink: &mut RegionSink) {
    let fdt = boot_info as u64;

    // (1) Usable RAM: the QEMU `virt` map, clamped to the identity gigabyte.
    let end = (DRAM_BASE + DRAM_SIZE).min(ID_RAM_HI);
    if end > DRAM_BASE {
        sink.push_usable(DRAM_BASE, end - DRAM_BASE);
    }

    // (2) Reserve the low-RAM window below the kernel image (DTB / boot params).
    sink.push_reserved(DRAM_BASE, IMAGE_LMA - DRAM_BASE);

    // (3) Reserve the exact DTB span wherever QEMU placed it (best-effort).
    if let Some(total) = fdt_totalsize(fdt) {
        sink.push_reserved(fdt, total as u64);
    }
}

